import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Select,
  Modal,
  Checkbox,
  SearchInput, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { createAccountSearchConfig, formatAccountDisplay } from '../../../components/search';
import { masterService } from '../../../services/master/masterService';
import type { MaterialGroupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { flattenMaterialGroupTree, materialGroupRowIndent } from '../../../utils/materialGroupTree';
import { isRootMaterialGroup } from '../../../services/master/materialGroupPayload';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogFormFooter,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogPagination,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListGrid,
  CatalogListMasterToolbarSection,
  CatalogListMasterListFooter,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogCodeReplaceProvider,
  CatalogListCodeCell,
  CatalogListHeaderFilters,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-nhom-vat-tu';
const CATALOG_KIND = 'material-groups';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const NhomVatTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<MaterialGroupDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [serverTotalCount, setServerTotalCount] = useState(0);
  const [accountName, setAccountName] = useState('');
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<MaterialGroupDto | null>(null);
  const [form, setForm] = useState<Partial<MaterialGroupDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const isSearchMode = search.trim().length > 0;
  const {
    page: serverPage,
    setPage: setServerPage,
    pageSize: serverPageSize,
    setPageSize: setServerPageSize,
    resetPage: resetServerPage,
  } = useCatalogListPaging();

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getMaterialGroups({
          search: search || undefined,
          page: isSearchMode ? serverPage : 1,
          pageSize: isSearchMode ? serverPageSize : 500,
        })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setServerTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải nhóm vật tư', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, isSearchMode, serverPage, serverPageSize, reloadKey, dispatch]);

  React.useEffect(() => {
    if (!modalOpen || !form.accountCode?.trim()) {
      if (!form.accountCode) setAccountName('');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccounts({ isActive: true, isDetail: true, page: 1, pageSize: 500 }).then(res => {
        if (!cancelled) {
          const a = res.items.find(x => x.code === form.accountCode);
          setAccountName(a?.name ?? '');
        }
      });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [modalOpen, form.accountCode]);

  const groupOpts = useMemo(
    () => items
      .filter(g => !editing || g.id !== editing.id)
      .map(g => ({
        value: String(g.id),
        label: `${'  '.repeat((g.level ?? 1) - 1)}${g.code} — ${g.name}`,
      })),
    [items, editing],
  );

  const displayRows = useMemo(
    () => (isSearchMode ? items : flattenMaterialGroupTree(items)),
    [items, isSearchMode],
  );

  const clientPaging = useCatalogPagination(displayRows);

  const page = isSearchMode ? serverPage : clientPaging.page;
  const setPage = isSearchMode ? setServerPage : clientPaging.setPage;
  const pageSize = isSearchMode ? serverPageSize : clientPaging.pageSize;
  const setPageSize = isSearchMode ? setServerPageSize : clientPaging.setPageSize;
  const totalCount = isSearchMode ? serverTotalCount : clientPaging.totalCount;
  const tableRows = isSearchMode ? items : clientPaging.pageItems;
  const batchSource = isSearchMode ? items : displayRows;

  const selection = useCatalogListSelection({
    rows: tableRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const resetPage = () => {
    resetServerPage();
    clientPaging.resetPage();
  };

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã nhóm';
    if (!form.name?.trim()) next.name = 'Nhập tên nhóm';
    return next;
  };

  const scrollToFirstError = () => {
    document
      .querySelector<HTMLElement>(`[data-testid^="${TEST_ID}-field-"]`)
      ?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = (parentId?: string) => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true, parentId: parentId ?? undefined });
    setAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: MaterialGroupDto) => {
    setViewOnlyShared(isSharedCatalogReadOnly(row));
    setEditing(row);
    setForm({ ...row, parentId: row.parentId ?? undefined });
    setAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstError();
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateMaterialGroup(editing.id, form);
      else await masterService.createMaterialGroup(form);
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật nhóm vật tư thành công' : 'Tạo nhóm vật tư thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? batchSource.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = batchSource.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = batchSource.find(r => r.id === id)!;
        return masterService.updateMaterialGroup(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} nhóm vật tư`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteMaterialGroup(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} nhóm vật tư`, type: 'success' });
    }
    refresh();
  };

  const showRootAccount = isRootMaterialGroup(form.parentId);

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
    <div className={`${styles.page} ${styles.catalogListPage}`} data-catalog-list-page>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-layer-group" /> Nhóm vật tư hàng hóa</h1>
        </div>
      </div>
      <CatalogListMasterToolbarSection
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={tableRows}
        onAdd={() => openAdd()}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
      />
      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách nhóm vật tư"
        showTableLoading={showTableLoading}
        footer={
          <CatalogListMasterListFooter
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        }
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch hideRefresh />
          </CatalogListHeaderFilters>
        )}
      >
        {displayRows.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy nhóm phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={tableRows}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            headerCells={(
              <>
                <th>Mã nhóm</th>
                <th>Tên nhóm</th>
                <CatalogCompanyTh />
                <th>Cấp</th>
                <th>Số VT</th>
                <th>TK hàng tồn</th>
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => {
              const indent = materialGroupRowIndent(r.level);
              return (
                <>
                  <td style={{ paddingLeft: indent }}>
                    <CatalogListCodeCell testIdPrefix={TEST_ID} code={r.code} />
                  </td>
                  <td style={{ paddingLeft: indent }}>{r.name}</td>
                  <CatalogCompanyTd label={r.companyName} />
                  <td>{r.level ?? '—'}</td>
                  <td>{r.materialCount ?? 0}</td>
                  <td>{r.accountCode ?? '—'}</td>
                  <td>
                    <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                      {r.isActive ? 'Dùng' : 'Ngưng'}
                    </span>
                  </td>
                </>
              );
            }}
          />
        )}
      </CatalogListShell>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={viewOnlyShared ? 'Xem nhóm vật tư dùng chung' : editing ? 'Sửa nhóm vật tư' : 'Thêm nhóm vật tư'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentId`}>
              <label className={styles.label}>Nhóm cha</label>
              <Select
                value={form.parentId != null ? String(form.parentId) : ''}
                placeholder="— Cấp 1 —"
                className={selectPlaceholderClass(form.parentId != null ? String(form.parentId) : '')}
                disabled={viewOnlyShared}
                onChange={e => {
                  markDirty();
                  const parentId = e.target.value || undefined;
                  setForm(f => ({
                    ...f,
                    parentId,
                    accountCode: isRootMaterialGroup(parentId) ? f.accountCode : undefined,
                  }));
                }}
                options={groupOpts}
              />
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã nhóm *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên nhóm *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            {showRootAccount && (
              <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
                <label className={styles.label}>TK hàng tồn kho (cấp 1)</label>
                <SearchInput
                  config={accountSearchConfig}
                  value={form.accountCode ?? ''}
                  disabled={viewOnlyShared}
                  primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
                  onChange={a => {
                    markDirty();
                    setForm(f => ({ ...f, accountCode: normalizeCode(a.code) }));
                    setAccountName(a.name);
                  }}
                  onClear={() => {
                    markDirty();
                    setForm(f => ({ ...f, accountCode: undefined }));
                    setAccountName('');
                  }}
                  showLabel={false}
                  showSecondaryInput={false}
                  placeholder="152, 155, 156..."
                />
              </div>
            )}
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              accountCode: form.accountCode,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                editing={editing ? { id: editing.id, code: editing.code } : null}
              />
              </>
            }
            saveDisabled={viewOnlyShared}
            activeDisabled={viewOnlyShared}
          />
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </div>
    </CatalogCodeReplaceProvider>
  );
};

export default NhomVatTuPage;
